import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2, speed):
        return np.linalg.norm(np.array(pos1) - np.array(pos2)) / speed

    def calculate_adjusted_centrality(customer_pos, unvisited_customers):
        if len(unvisited_customers) < 2:
            return 0
        distances = [np.linalg.norm(np.array(customer_pos) - np.array(other_pos)) for other_pos in unvisited_customers]
        return np.var(distances)

    def calculate_score(travel_time, adjusted_centrality, customer_index):
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[customer_index]

        if arrival_time > end_window:
            return float('inf')  # High penalty for missing the time window

        buffer_penalty = max(0, start_window - arrival_time)
        urgency = 1.0 / (end_window - current_time) if end_window > current_time else float('inf')

        return travel_time + 3 * buffer_penalty - 0.5 * urgency + 0.4 * adjusted_centrality

    best_node = None
    best_score = float('inf')

    for index, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        adjusted_centrality = calculate_adjusted_centrality(customer_pos, unvisited_customers)
        score = calculate_score(travel_time, adjusted_centrality, index)

        if score < best_score:
            best_score = score
            best_node = index

    return best_node
